128	func (f *CommandFactory) runAgentExecuteLoopImpl(cmd *cobra.Command, treatPassthroughAsOpaque bool, tryTargetBeadID string) error {
129		spec, dispatch, err := parseExecuteLoopSpec(cmd, treatPassthroughAsOpaque)
130		if err != nil {
131			return err
132		}
133		projectRoot := resolveProjectRoot(spec.ProjectRoot, f.WorkingDir)
134		spec.ProjectRoot = projectRoot
135		if tryTargetBeadID != "" {
136			spec.Mode = executeloop.ModeOnce
137			spec.IdleInterval = executeloop.Duration{}
138		}
139	
140		noRoutingFlags := spec.Harness == "" && spec.Model == "" && spec.Provider == "" &&
141			spec.Profile == "" && spec.MinPower == 0 &&
142			spec.MaxPower == 0 && !cmd.Flags().Changed("harness") &&
143			!cmd.Flags().Changed("model") && !cmd.Flags().Changed("provider") &&
144			!cmd.Flags().Changed("profile") &&
145			!cmd.Flags().Changed("min-power") && !cmd.Flags().Changed("max-power")
146		autoInferPowerClass := noRoutingFlags && !projectHasRoutingConfig(projectRoot)
147	
148		if !spec.OpaquePassthrough {
149			if err := agent.ValidateForExecuteLoopViaService(cmd.Context(), f.WorkingDir, spec.Harness, spec.Model, spec.Provider); err != nil {
150				return fmt.Errorf("execute-loop: %w", err)
151			}
152		}
153	
154		store := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
155	
156		loopSessionID := fmt.Sprintf("agent-loop-%d", time.Now().UnixNano())
157		loopLogDir := filepath.Join(projectRoot, agent.DefaultLogDir)
158		_ = os.MkdirAll(loopLogDir, 0o755)
159		loopLogPath := filepath.Join(loopLogDir, loopSessionID+".jsonl")
160		var loopSink io.Writer
161		if lf, err := os.OpenFile(loopLogPath, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0o644); err == nil {
162			loopSink = lf
163			defer lf.Close() //nolint:errcheck
164		}
165	
166		probeIdent := workerprobe.Identity{
167			ProjectRoot:  projectRoot,
168			Harness:      spec.Harness,
169			Model:        spec.Model,
170			ExecutorPID:  os.Getpid(),
171			ExecutorHost: hostnameOrEmpty(),
172			StartedAt:    time.Now().UTC(),
173		}
174		probe := workerprobe.New(probeIdent, workerprobe.Config{AddrFunc: serverpkg.ReadServerAddr})
175		probeCtx, probeCancel := context.WithCancel(context.Background())
176		probe.Start(probeCtx)
177		defer func() {
178			probeCancel()
179			probe.Stop()
180		}()
181		if loopSink != nil {
182			loopSink = workerprobe.TeeJSONL(loopSink, probe)
183		} else {
184			loopSink = workerprobe.TeeJSONL(io.Discard, probe)
185		}
186	
187		localCoord := serverpkg.NewLocalLandCoordinator(projectRoot, agent.RealLandingGitOps{})
188		defer localCoord.Stop()
189	
190		var reviewer agent.BeadReviewer
191		if !spec.NoReview {
192			reviewer = &agent.DefaultBeadReviewer{
193				ProjectRoot: projectRoot,
194				BeadStore:   bead.NewStore(filepath.Join(projectRoot, ".ddx")),
195				BeadEvents:  bead.NewStore(filepath.Join(projectRoot, ".ddx")),
196				Harness:     spec.ReviewHarness,
197				Model:       spec.ReviewModel,
198			}
199		}
200	
201		spec.Profile = agent.NormalizeRoutingProfile(spec.Profile)
202	
203		overrides := config.CLIOverrides{
204			Assignee:          resolveClaimAssignee(),
205			Harness:           spec.Harness,
206			Model:             spec.Model,
207			Provider:          spec.Provider,
208			Profile:           spec.Profile,
209			Effort:            spec.Effort,
210			MinPower:          spec.MinPower,
211			MaxPower:          spec.MaxPower,
212			OpaquePassthrough: spec.OpaquePassthrough,
213		}
214		rcfg, err := config.LoadAndResolve(projectRoot, overrides)
215		if err != nil {
216			return fmt.Errorf("load resolved config: %w", err)
217		}
218	
219		resourceChecker := buildCLIResourceChecker(projectRoot, f.resourceCheckerOverride)
220		if _, err := resourceChecker.Check(cmd.Context()); err != nil {
221			var resourceErr *agent.ResourceExhaustedError
222			if errors.As(err, &resourceErr) {
223				_, _ = fmt.Fprintln(cmd.OutOrStdout(), agent.ResourceExhaustedStopMessage)
224			}
225			return err
226		}
227	
228		var qualityRunner agent.AgentRunner
229		if f.AgentRunnerOverride != nil {
230			qualityRunner = f.AgentRunnerOverride
231		}
232		lintHook := agent.NewPreDispatchLintHook(projectRoot, store, rcfg, nil, qualityRunner)
233		intakeLog := cmd.OutOrStdout()
234		if dispatch.JSON == "true" {
235			intakeLog = io.Discard
236		}
237		innerIntakeHook := agent.NewPreClaimIntakeHookWithLogVerbose(projectRoot, store, rcfg, nil, qualityRunner, intakeLog, f.viperInstance.GetBool("verbose"))
238		intakeHook := agent.NewACQualityPreClaimGate(store, rcfg.BeadQualityMode(), rcfg.ACQualityMinScore(), innerIntakeHook)
239		triageHook := agent.NewPostAttemptTriageHook(projectRoot, store, rcfg, nil, qualityRunner, nil)
240		proseHook := f.proseEvidenceHookOverride
241		if proseHook == nil {
242			proseHook = agent.NewDefaultProseEvidenceHook(agent.ProseEvidenceConfig{
243				ProjectRoot: projectRoot,
244				Events:      bead.NewStore(filepath.Join(projectRoot, ".ddx")),
245				Actor:       resolveClaimAssignee(),
246				Source:      "ddx work",
247			})
248		}
249		decompositionHook := agent.NewPreClaimDecompositionHook(store, qualityRunner, rcfg, projectRoot)
250		recoveryHook := agent.NewAutoRecoveryPostLadderExhaustionHook(store, qualityRunner, rcfg, projectRoot, agent.AutoRecoveryConfig{
251			MaxRecoveryCostUSD: spec.MaxRecoveryCostUSD,
252			MaxBeadCostUSD:     spec.MaxBeadCostUSD,
253		})
254	
255		harnessBilledLookup := func(harnessName string) bool {
256			svc, svcErr := agent.NewServiceFromWorkDir(f.WorkingDir)
257			if svcErr != nil {
258				return true
259			}
260			infos, err := svc.ListHarnesses(context.Background())
261			if err != nil {
262				return true
263			}
264			for _, h := range infos {
265				if h.Name == harnessName {
266					return escalation.CountsTowardCostCap(h.CostClass == "local", h.Billing == agentlib.BillingModelSubscription, h.CostClass)
267				}
268			}
269			return true
270		}
271	
272		costCap := escalation.NewCostCapTracker(spec.MaxCostUSD, harnessBilledLookup)
273		profileSelector := newImplementationProfileSelector(projectRoot)
274		accumulateBilledCost := func(report agent.ExecuteBeadReport) {
275			costCap.Add(report.Harness, report.CostUSD)
276		}
277		costCapTripped := func() (work.StopDecision, agent.ExecuteBeadReport, bool) {
278			if _, tripped := costCap.Tripped(); !tripped {
279				return work.StopDecision{}, agent.ExecuteBeadReport{}, false
280			}
281			spent := costCap.Spent()
282			decision, _ := work.ClassifyStop(work.StopInput{Budget: true})
283			return decision, agent.ExecuteBeadReport{
284				Status: agent.ExecuteBeadStatusExecutionFailed,
285				Detail: fmt.Sprintf("cost cap reached: $%.2f billed >= $%.2f cap; raise the cap or set 0 to disable. Subscription and local providers do not count.", spent, spec.MaxCostUSD),
286			}, true
287		}
288	
289		singlePolicyAttempt := func(ctx context.Context, beadID string, requestedMinPower int, requestedProfile string, inferredPolicy escalation.PowerClass, routingNote string, resolvedHarness, resolvedProvider, resolvedModel string) (agent.ExecuteBeadReport, error) {
290			gitOps := &agent.RealGitOps{}
291			attemptProvider := spec.Provider
292			if resolvedProvider != "" {
293				attemptProvider = resolvedProvider
294			}
295			reportFromResult := func(res *agent.ExecuteBeadResult) agent.ExecuteBeadReport {
296				report := agent.ReportFromExecuteBeadResult(res, string(inferredPolicy))
297				report.InferredPowerClass = string(inferredPolicy)
298				report.RequestedProfile = requestedProfile
299				report.RoutingIntentNote = routingNote
300				return report
301			}
302			loopOverrides := config.CLIOverrides{
303				Harness:           resolvedHarness,
304				Model:             resolvedModel,
305				Provider:          attemptProvider,
306				Profile:           requestedProfile,
307				Effort:            spec.Effort,
308				MinPower:          requestedMinPower,
309				MaxPower:          spec.MaxPower,
310				OpaquePassthrough: spec.OpaquePassthrough,
311			}
312			requestTimeout := spec.RequestTimeout.Duration
313			if requestTimeout > 0 {
314				loopOverrides.ProviderRequestTimeout = &requestTimeout
315			}
316			attemptRcfg, _ := config.LoadAndResolve(projectRoot, loopOverrides)
317			res, execErr := agent.ExecuteBeadWithConfig(ctx, projectRoot, beadID, attemptRcfg, executeLoopAttemptRuntime(
318				spec,
319				cmd.OutOrStdout(),
320				bead.NewStore(filepath.Join(projectRoot, ".ddx")),
321				f.AgentRunnerOverride,
322				resourceChecker,
323			), gitOps)
324			if execErr != nil && res == nil {
325				return agent.ExecuteBeadReport{}, execErr
326			}
327			if res != nil && agent.IsResourceExhaustedStatus(res.Status) {
328				return reportFromResult(res), nil
329			}
330			if execErr != nil {
331				agent.MarkResultExecutionError(res, execErr)
332				return reportFromResult(res), nil
333			}
334			if res != nil && res.ResultRev != "" && res.ResultRev != res.BaseRev && res.ExitCode == 0 {
335				targetBead, _ := store.Get(context.Background(), beadID)
336				landRes, _, landErr := agent.SubmitWithPreMergeChecks(
337					ctx, projectRoot, targetBead, res,
338					func(req agent.LandRequest) (*agent.LandResult, error) { return localCoord.Submit(req) },
339					bead.NewStore(filepath.Join(projectRoot, ".ddx")),
340					resolveClaimAssignee(), "ddx work",
341					nil,
342				)
343				if landErr == nil {
344					agent.ApplyLandResultToExecuteBeadResult(res, landRes)
345					_ = agent.WriteExecuteBeadResultArtifact(projectRoot, res)
346				} else {
347					agent.MarkResultLandError(projectRoot, res, landErr)
348					_ = agent.WriteExecuteBeadResultArtifact(projectRoot, res)
349					return reportFromResult(res), nil
350				}
351			} else if res != nil && (res.Outcome == agent.ExecuteBeadOutcomeTaskFailed || res.ExitCode != 0) {
352				if res.ResultRev != "" && res.ResultRev != res.BaseRev {
353					res.Outcome = "preserved"
354				} else {
355					res.Outcome = "error"
356				}
357				res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
358			} else if res != nil && res.ResultRev == res.BaseRev {
359				res.Outcome = "no-changes"
360				res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
361			}
362			return reportFromResult(res), nil
363		}
364	
365		var ladderOnce sync.Once
366		var ladder escalationFloorFinder
367		loadLadder := func() escalationFloorFinder {
368			ladderOnce.Do(func() {
369				ladder = powerladder.NewLadder(nil)
370				svc, svcErr := agent.ResolveServiceFromWorkDir(projectRoot)
371				if svcErr != nil {
372					return
373				}
374				modelFilter := agentlib.ModelFilter{}
375				if spec.Harness != "" {
376					modelFilter.Harness = spec.Harness
377				}
378				modelCtx, cancel := context.WithTimeout(cmd.Context(), 2*time.Second)
379				defer cancel()
380				models, listErr := svc.ListModels(modelCtx, modelFilter)
381				if listErr != nil {
382					return
383				}
384				ladder = powerladder.NewLadder(models)
385			})
386			return ladder
387		}
388	
389		worker := &agent.ExecuteBeadWorker{
390			Store:    store,
391			Reviewer: reviewer,
392			EscalationNextFloor: func(actualPower int) (int, error) {
393				return nextEscalationFloor(loadLadder(), actualPower)
394			},
395			Executor: agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
396				targetBead, err := store.Get(context.Background(), beadID)
397				if err != nil {
398					return agent.ExecuteBeadReport{}, err
399				}
400				inferredPolicy := escalation.PowerClass("")
401				if autoInferPowerClass {
402					inferredPolicy = escalation.InferPowerClass(targetBead)
403				}
404				initialMinPower, unavailableReport, unavailable := investigationRetryInitialMinPowerWithInference(targetBead, rcfg.MinPower(), spec.MaxPower, loadLadder(), false)
405				if unavailable {
406					return unavailableReport, nil
407				}
408				if spec.Provider == "" && spec.Model == "" {
409					if learnedMinPower, learnedUnavailableReport, learned := recentProviderConnectivityMinPower(store, time.Now().UTC(), initialMinPower, spec.MaxPower, loadLadder()); learned {
410						if learnedUnavailableReport.Status != "" {
411							learnedUnavailableReport.BeadID = beadID
412							return learnedUnavailableReport, nil
413						}
414						if learnedMinPower > initialMinPower {
415							initialMinPower = learnedMinPower
416						}
417					}
418				}
419				initialProfile := spec.Profile
420				initialRoutingNote := ""
421				if autoInferPowerClass {
422					if selection, selectErr := profileSelector.Select(ctx, inferredPolicy, initialMinPower); selectErr == nil && selection.Name != "" {
423						initialProfile = selection.Name
424						initialRoutingNote = selection.Note
425						if spec.MaxPower > 0 && initialMinPower > 0 && initialMinPower >= spec.MaxPower {
426							unavailableReport := smartRouteUnavailableReport(targetBead, initialMinPower, spec.MaxPower, nil)
427							unavailableReport.InferredPowerClass = string(inferredPolicy)
428							unavailableReport.RequestedProfile = initialProfile
429							unavailableReport.RoutingIntentNote = initialRoutingNote
430							return unavailableReport, nil
431						}
432					} else {
433						initialMinPower, unavailableReport, unavailable = zeroConfigInferredMinPower(targetBead, initialMinPower, spec.MaxPower, loadLadder())
434						if unavailable {
435							unavailableReport.InferredPowerClass = string(inferredPolicy)
436							return unavailableReport, nil
437						}
438					}
439				}
440				perBeadBudget := spec.MaxBeadCostUSD
441				if override, ok := escalation.ParseBeadBudgetLabel(targetBead.Labels); ok {
442					perBeadBudget = override
443				}
444				perBeadTracker := escalation.NewPerBeadCostTracker(perBeadBudget, harnessBilledLookup)
445				report, err := runEscalatingPowerAttempts(
446					ctx,
447					initialMinPower,
448					loadLadder(),
449					func(ctx context.Context, requestedMinPower int) (agent.ExecuteBeadReport, error) {
450						requestProfile := initialProfile
451						routingNote := initialRoutingNote
452						if autoInferPowerClass {
453							if selection, selectErr := profileSelector.Select(ctx, inferredPolicy, requestedMinPower); selectErr == nil {
454								// Empty selection means no no-extra-requirement policy covers this
455								// retry floor. Drop the stale lower policy and send MinPower-only so
456								// Fizeau can route or report no eligible candidate from live config.
457								requestProfile = selection.Name
458								if requestProfile == "" {
459									routingNote = ""
460								} else if selection.Note != "" {
461									routingNote = selection.Note
462								}
463							}
464						}
465						return singlePolicyAttempt(ctx, beadID, requestedMinPower, requestProfile, inferredPolicy, routingNote, spec.Harness, spec.Provider, spec.Model)
466					},
467					nil,
468					perBeadTracker,
469				)
470				if err == nil {
471					accumulateBilledCost(report)
472				}
473				return report, err
474			}),
475		}
476	
477		cliLandingOps := agent.RealLandingGitOps{}
478		progressLog := cmd.OutOrStdout()
479		cleanupLog := cmd.ErrOrStderr()
480		jsonOutput := dispatch.JSON == "true"
481		if jsonOutput {
482			progressLog = io.Discard
483			cleanupLog = io.Discard
484		}
485		result, err := worker.Run(cmd.Context(), rcfg, agent.ExecuteBeadLoopRuntime{
486			Mode:                         spec.Mode,
487			IdleInterval:                 spec.IdleInterval.Duration,
488			Log:                          progressLog,
489			CleanupLog:                   cleanupLog,
490			EventSink:                    loopSink,
491			WorkerID:                     resolveClaimAssignee(),
492			ProjectRoot:                  projectRoot,
493			CleanupRunner:                agent.NewExecutionCleanupManager(projectRoot, &agent.RealGitOps{}),
494			ResourceChecker:              resourceChecker,
495			BinaryRefreshCheck:           f.buildWorkBinaryRefreshCheck(cmd, projectRoot, tryTargetBeadID),
496			SessionID:                    loopSessionID,
497			PreClaimHook:                 buildCLIPreClaimHook(projectRoot, cliLandingOps),
498			PreClaimIntakeHook:           intakeHook,
499			PreClaimTimeout:              spec.PreClaimTimeout.Duration,
500			PreDispatchLintHook:          lintHook,
501			PostAttemptTriageHook:        triageHook,
502			ProseEvidenceHook:            proseHook,
503			PostAttemptDecompositionHook: decompositionHook,
504			BudgetStop:                   costCapTripped,
505			NoReview:                     spec.NoReview,
506			TargetBeadID:                 tryTargetBeadID,
507			ReviewCostCap:                costCap,
508			OnAttemptFinalized:           buildAttemptMetricsHook(projectRoot, store, spec.Profile),
509			PostLadderExhaustionHook:     recoveryHook,
510		})
511		if err != nil && result != nil && (errors.Is(err, context.Canceled) || errors.Is(err, context.DeadlineExceeded)) {
512			_ = writeExecuteLoopResult(cmd.OutOrStdout(), projectRoot, result, jsonOutput)
513		}
514		if err != nil {
515			return err
516		}
517		if result != nil && result.ExitReason == "binary_refresh" {
518			return nil
519		}
520		return writeExecuteLoopResult(cmd.OutOrStdout(), projectRoot, result, jsonOutput)
521	}
