523	func buildAttemptMetricsHook(projectRoot string, store *bead.Store, profile string) func(agent.ExecuteBeadReport) {
524		return func(report agent.ExecuteBeadReport) {
525			if report.AttemptID == "" {
526				return
527			}
528			specID := ""
529			if report.BeadID != "" && store != nil {
530				if b, err := store.Get(context.Background(), report.BeadID); err == nil {
531					specID, _ = b.Extra["spec-id"].(string)
532				}
533			}
534			tsEnd := attemptmetrics.Rfc3339(time.Now().UTC())
535			tsStart := ""
536			if report.DurationMS > 0 {
