115	func recentProviderConnectivityMinPower(store *bead.Store, now time.Time, baseMinPower, maxPower int, ladder escalationFloorFinder) (int, agent.ExecuteBeadReport, bool) {
116		if store == nil || ladder == nil {
117			return baseMinPower, agent.ExecuteBeadReport{}, false
118		}
119		beads, err := store.List("", "", nil)
120		if err != nil {
121			return baseMinPower, agent.ExecuteBeadReport{}, false
122		}
123		floor := baseMinPower
124		for _, b := range beads {
125			events, err := store.Events(b.ID)
126			if err != nil {
127				continue
128			}
129			if next, ok := recentProviderConnectivityMinPowerFromEvents(events, now, floor, maxPower, ladder); ok {
130				if next >= maxPower && maxPower > 0 {
131					return baseMinPower, smartRouteUnavailableReport(&b, next, maxPower, nil), true
132				}
133				if next > floor {
134					floor = next
135				}
136			}
137		}
138		if floor > baseMinPower {
139			return floor, agent.ExecuteBeadReport{}, true
140		}
141		return baseMinPower, agent.ExecuteBeadReport{}, false
142	}
