144	func recentProviderConnectivityMinPowerFromEvents(events []bead.BeadEvent, now time.Time, baseMinPower, maxPower int, ladder escalationFloorFinder) (int, bool) {
145		if len(events) == 0 || ladder == nil {
146			return baseMinPower, false
147		}
148		floor := baseMinPower
149		var last recentRouteEvent
150		for _, ev := range events {
151			if ev.CreatedAt.IsZero() || now.Sub(ev.CreatedAt) > agent.ProviderUnavailableCooldown || ev.CreatedAt.After(now.Add(time.Minute)) {
152				continue
153			}
154			if route, ok := routeEventFromBeadEvent(ev); ok {
155				last = route
156				continue
157			}
158			if ev.Kind == "route-failure" {
159				route, ok := routeFailureEventFromBeadEvent(ev)
160				if !ok {
161					continue
162				}
163				if next, ok := nextFloorForRecentConnectivity(route.ActualPower, maxPower, ladder); ok && next > floor {
164					floor = next
165				}
166				continue
167			}
168			if ev.Kind == "execute-bead" && strings.EqualFold(strings.TrimSpace(ev.Summary), "execution_failed") && isProviderConnectivityEventBody(ev.Body) && last.Provider != "" {
169				if next, ok := nextFloorForRecentConnectivity(last.ActualPower, maxPower, ladder); ok && next > floor {
170					floor = next
171				}
172			}
173		}
174		return floor, floor > baseMinPower
175	}
