267	func resolvePowerFloor(powerClass policyescalation.PowerClass, ladder escalationFloorFinder) (int, bool) {
268		switch powerClass {
269		case policyescalation.PowerSmart:
270			floor, err := highestViableEscalationFloor(ladder)
271			if err != nil {
272				return 0, false
273			}
274			return floor, true
275		case policyescalation.PowerStandard:
276			first, err := nextEscalationFloor(ladder, 0)
277			if err != nil {
278				return 0, false
279			}
280			second, err := nextEscalationFloor(ladder, first)
281			if err != nil {
282				return first, true
283			}
284			return second, true
285		default:
286			return 0, false
287		}
288	}
