368	func runEscalatingPowerAttempts(
369		ctx context.Context,
370		initialMinPower int,
371		ladder escalationFloorFinder,
372		attempt func(context.Context, int) (agent.ExecuteBeadReport, error),
373		recordAttempt func(agent.ExecuteBeadReport),
374		perBeadTracker *policyescalation.PerBeadCostTracker,
375	) (agent.ExecuteBeadReport, error) {
376		minPower := initialMinPower
377		for {
378			report, err := attempt(ctx, minPower)
379			if recordAttempt != nil && report.BeadID != "" {
380				recordAttempt(report)
381			}
382			if perBeadTracker != nil {
383				perBeadTracker.Add(report.Harness, report.CostUSD)
384			}
385			if err != nil {
386				return report, err
387			}
388			if report.Disrupted || isBudgetExhaustedFailure(report) || !policyescalation.ShouldEscalate(report.Status) || policyescalation.IsInfrastructureFailure(report.Status, report.Detail) {
389				return report, nil
390			}
391			if perBeadTracker != nil {
392				if detail, tripped := perBeadTracker.Tripped(); tripped {
393					report.Status = agent.ExecuteBeadStatusExecutionFailed
394					report.Detail = detail
395					report.CostUSD = perBeadTracker.Spent()
396					return report, nil
397				}
398			}
399			var nextPower int
400			if report.ActualPower > 0 {
401				// Evidence-driven retry: bump MinPower one above the actual power
402				// the previous route ran at. Profile reselection in the caller's
403				// attempt callback moves to a stronger policy band only when the
404				// new floor exceeds the current band's MaxPower; otherwise the
405				// same policy intent is preserved so DDx does not duplicate
406				// Fizeau policy bounds as initial dispatch floors.
407				nextPower = report.ActualPower + 1
408			} else {
409				next, nextErr := nextEscalationFloor(ladder, minPower)
410				if nextErr != nil {
411					return report, nil
412				}
413				nextPower = next
414			}
415			minPower = nextPower
416		}
417	}
